No `dependencies` and no `registryDependencies` since we don't import any other shadcn components.

### 5. Complete File Specifications

#### 5.1 `apps/v4/registry/new-york-v4/ui/stepper.tsx` -- Full Content

```typescript
"use client"

import * as React from "react"
import { CheckIcon } from "lucide-react"

import { cn } from "@/lib/utils"

type StepperContextType = {
  activeStep: number
  orientation: "horizontal" | "vertical"
}

const StepperContext = React.createContext<StepperContextType | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

type StepperItemContextType = {
  step: number
  state: "completed" | "active" | "inactive"
}

const StepperItemContext = React.createContext<StepperItemContextType | null>(
  null
)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }
  return context
}

function Stepper({
  activeStep,
  orientation = "horizontal",
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  activeStep: number
  orientation?: "horizontal" | "vertical"
}) {
  return (
    <StepperContext.Provider value={{ activeStep, orientation }}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "group/stepper flex gap-4",
          orientation === "horizontal"
            ? "flex-row items-center"
            : "flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

function StepperItem({
  step,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  step: number
}) {
  const { activeStep } = useStepper()

  const state: "completed" | "active" | "inactive" =
    step < activeStep
      ? "completed"
      : step === activeStep
        ? "active"
        : "inactive"

  return (
    <StepperItemContext.Provider value={{ step, state }}>
      <div
        data-slot="stepper-item"
        data-state={state}
        className={cn(
          "flex items-center gap-3 last:flex-[0_0_auto]",
          "flex-1",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { state, step } = useStepperItem()

  return (
    <button
      data-slot="stepper-trigger"
      data-state={state}
      className={cn(
        "inline-flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-sm font-medium transition-colors outline-none focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50 disabled:pointer-events-none disabled:opacity-50",
        state === "completed" &&
          "border-primary bg-primary text-primary-foreground",
        state === "active" && "border-primary text-primary",
        state === "inactive" && "border-muted text-muted-foreground",
        className
      )}
      {...props}
    >
      {children ?? (state === "completed" ? (
        <CheckIcon className="size-4" />
      ) : (
        step + 1
      ))}
    </button>
  )
}

function StepperTitle({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { state } = useStepperItem()

  return (
    <div
      data-slot="stepper-title"
      data-state={state}
      className={cn(
        "text-sm font-medium",
        state === "inactive" && "text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { state } = useStepperItem()

  return (
    <div
      data-slot="stepper-description"
      data-state={state}
      className={cn(
        "text-sm text-muted-foreground",
        state === "inactive" && "text-muted-foreground/60",
        className
      )}
      {...props}
    />
  )
}

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()
  const { state } = useStepperItem()

  const isCompleted = state === "completed"

  return (
    <div
      data-slot="stepper-separator"
      data-state={isCompleted ? "completed" : "inactive"}
      className={cn(
        "transition-colors",
        orientation === "horizontal" ? "h-0.5 flex-1" : "ml-4 w-0.5 min-h-4",
        isCompleted ? "bg-primary" : "bg-border",
        className
      )}
      {...props}
    />
  )
}

function StepperContent({
  className,
  children,
  ...props
}: React.ComponentProps<"div">) {
  const { state } = useStepperItem()

  if (state !== "active") return null

  return (
    <div
      data-slot="stepper-content"
      data-state={state}
      className={cn("text-sm", className)}
      {...props}
    >
      {children}
    </div>
  )
}

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
}
```

**Important note on step numbering**: The `step` prop is 0-indexed (matching array indices), but the trigger displays `step + 1` so users see "1, 2, 3" in the UI. This is the natural convention when mapping over arrays.

#### 5.2 `apps/v4/registry/new-york-v4/examples/stepper-demo.tsx` -- Full Content

```typescript
"use client"

import * as React from "react"

import { Button } from "@/registry/new-york-v4/ui/button"
import {
  Stepper,
  StepperDescription,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

const steps = [
  {
    title: "Step 1",
    description: "Create your account",
  },
  {
    title: "Step 2",
    description: "Verify your email",
  },
  {
    title: "Step 3",
    description: "Complete your profile",
  },
]

export default function StepperDemo() {
  const [activeStep, setActiveStep] = React.useState(0)

  return (
    <div className="flex w-full max-w-lg flex-col gap-6">
      <Stepper activeStep={activeStep}>
        {steps.map((s, index) => (
          <StepperItem key={index} step={index}>
            <StepperTrigger onClick={() => setActiveStep(index)} />
            <div className="flex flex-col">
              <StepperTitle>{s.title}</StepperTitle>
              <StepperDescription>{s.description}</StepperDescription>
            </div>
            {index < steps.length - 1 && <StepperSeparator />}
          </StepperItem>
        ))}
      </Stepper>
      <div className="flex justify-end gap-2">
        <Button
          variant="outline"
          onClick={() => setActiveStep((prev) => Math.max(0, prev - 1))}
          disabled={activeStep === 0}
        >
          Previous
        </Button>
        <Button
          onClick={() =>
            setActiveStep((prev) => Math.min(steps.length - 1, prev + 1))
          }
          disabled={activeStep === steps.length - 1}
        >
          Next
        </Button>
      </div>
    </div>
  )
}
```

